"""
This module gathers all Private Known VLRs. These VLRs are not official within
the las convention but are useful to internal processes.
"""

from typing import Tuple

from laspy.vlrs import BaseKnownVLR


class InnersCountVlr(BaseKnownVLR):
    def __init__(self) -> None:
        super().__init__(
            description="Number of points from the start of the coordinates list"
            "which corresponds to the inner area (as opposed to the"
            "padded area) after a tiling process has been launched. "
            "Defaults to -1 (the whole cloud)."
        )
        self.inners_count: int = -1

    def record_data_bytes(self) -> bytes:
        return self.inners_count.to_bytes(2**16 - 1, byteorder="little")

    @staticmethod
    def official_user_id() -> str:
        return "geosat"

    @staticmethod
    def official_record_ids() -> Tuple[int, ...]:
        return (3000,)

    def parse_record_data(self, record_data: bytes) -> None:
        self.inners_count = int.from_bytes(record_data, "little")

    def set_data(self, inners: int) -> None:
        self.inners_count = inners

    def get_data(self) -> int:
        return self.inners_count
